// Script Continued Below
var templatesMap = {};
	var	nameIter = {};
		getRecords();

		function getRecords(){
			var gr_PT_Rename = new GlideRecord("x_153465_discovert_discover_routing_template");
			gr_PT_Rename.query();
			while(gr_PT_Rename.next()){
				var tempName;
				try {
					tempName = gr_PT_Rename.getValue("template_name");

					var templateName = gr_PT_Rename.template_name.toString().toLowerCase();
					var trackChange = false;
					if(templatesMap[templateName]){
						var num = ++nameIter[templateName];
						var changedName = gr_PT_Rename.template_name +  ' - Copy (' + num +')';
						gr_PT_Rename.template_name = changedName;
						trackChanges = true;
					}else{
						templatesMap[templateName] = true;
						nameIter[templateName] = 0;
					}
					if(trackChange) {
						gr_PT_Rename.update();
					}
				} catch(e){
					gs.error("Template Name:" + tempName + " - Error in 'Process Templates - Rename Duplicates' - exception: " + e);
				}
			}
		}
